import{_ as t,o as e,c as r,a2 as d}from"./chunks/framework.Cr-Z7ngm.js";const b=JSON.parse('{"title":"基金买入与卖出规则","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"funds-and-wealth/fund-trading-rules.md","filePath":"zh-CN/funds-and-wealth/fund-trading-rules.md"}'),l={name:"funds-and-wealth/fund-trading-rules.md"};function i(h,a,n,o,s,u){return e(),r("div",null,[...a[0]||(a[0]=[d('<h1 id="基金买入与卖出规则" tabindex="-1">基金买入与卖出规则 <a class="header-anchor" href="#基金买入与卖出规则" aria-label="Permalink to &quot;基金买入与卖出规则&quot;">​</a></h1><p>基金交易 T 日定义、买卖截止时间、撤单规则及交易金额要求。</p><h2 id="t-日定义" tabindex="-1">T 日定义 <a class="header-anchor" href="#t-日定义" aria-label="Permalink to &quot;T 日定义&quot;">​</a></h2><p>基金交易以每天 <strong>12:00（北京时间）</strong> 为当日截止时间。12:00 前提交的申请按当日（T 日）净值处理；12:00 后提交的申请，顺延至下一个交易日（T+1 日）处理。</p><h2 id="买入规则" tabindex="-1">买入规则 <a class="header-anchor" href="#买入规则" aria-label="Permalink to &quot;买入规则&quot;">​</a></h2><h3 id="正常买入流程" tabindex="-1">正常买入流程 <a class="header-anchor" href="#正常买入流程" aria-label="Permalink to &quot;正常买入流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 12:00 前提交</td><td>按 T 日净值确认</td></tr><tr><td>T+3 日</td><td>确认买入份额，份额到账</td></tr><tr><td>T+4 日起</td><td>可查看持有收益</td></tr></tbody></table><h3 id="撤单规则" tabindex="-1">撤单规则 <a class="header-anchor" href="#撤单规则" aria-label="Permalink to &quot;撤单规则&quot;">​</a></h3><ul><li>T 日 12:00 前，可撤销尚未确认的买入申请</li><li>T 日 12:00 后，买入申请不可撤单</li></ul><h2 id="卖出规则" tabindex="-1">卖出规则 <a class="header-anchor" href="#卖出规则" aria-label="Permalink to &quot;卖出规则&quot;">​</a></h2><h3 id="正常卖出流程" tabindex="-1">正常卖出流程 <a class="header-anchor" href="#正常卖出流程" aria-label="Permalink to &quot;正常卖出流程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>时间节点</th><th>说明</th></tr></thead><tbody><tr><td>T 日 12:00 前提交</td><td>按 T 日净值确认卖出金额</td></tr><tr><td>T+3 日</td><td>确认卖出净值，份额扣除</td></tr><tr><td>T+3 日起 7 个交易日内</td><td>资金到账</td></tr></tbody></table><h3 id="撤单规则-1" tabindex="-1">撤单规则 <a class="header-anchor" href="#撤单规则-1" aria-label="Permalink to &quot;撤单规则&quot;">​</a></h3><ul><li>T 日 12:00 前，可撤销尚未确认的卖出申请</li><li>T 日 12:00 后，卖出申请不可撤单</li></ul><h2 id="交易金额要求" tabindex="-1">交易金额要求 <a class="header-anchor" href="#交易金额要求" aria-label="Permalink to &quot;交易金额要求&quot;">​</a></h2><ul><li><strong>起购金额</strong>：首次买入的最低金额，以基金详情页显示为准</li><li><strong>最小卖出份额</strong>：每次卖出的最低份额数量，以基金详情页显示为准</li></ul><p>不同基金的起购金额和最小卖出份额可能不同，请以具体基金详情页的说明为准。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/funds-and-wealth/基金收费规则">基金收费规则</a> — 各类基金的收费标准</li></ul>',19)])])}const f=t(l,[["render",i]]);export{b as __pageData,f as default};
